typedef union _PCI_EXPRESS_CORRECTABLE_ERROR_MASK {   struct {
ULONG ReceiverError  :1;     ULONG Reserved1  :5;
ULONG BadTLP  :1;     ULONG BadDLLP  :1;
ULONG ReplayNumRollover  :1;     ULONG Reserved2  :3;
ULONG ReplayTimerTimeout  :1;
ULONG AdvisoryNonFatalError  :1;
ULONG Reserved3  :18;   };
ULONG  AsULONG;
} PCI_EXPRESS_CORRECTABLE_ERROR_MASK, *PPCI_CORRECTABLE_ERROR_MASK; 成员
DUMMYSTRUCTNAME
DUMMYSTRUCTNAME.ReceiverError
一个位，指示报告接收方错误将被屏蔽。
DUMMYSTRUCTNAME.Reserved1 保留。
DUMMYSTRUCTNAME.BadTLP
指示报告错误的事务层数据包（TLP）的单个位将被屏蔽。 DUMMYSTRUCTNAME.BadDLLP
一个位，指示报告错误的数据链接层数据包（DLLP）将被屏蔽。 DUMMYSTRUCTNAME.ReplayNumRollover
一个位，指示对重新传输重试缓冲区的次数进行计数的计数器滚动更新的报告被屏蔽。
DUMMYSTRUCTNAME.Reserved2 保留。
DUMMYSTRUCTNAME.ReplayTimerTimeout
一个位，指示重播计时器的超时报告被屏蔽。
DUMMYSTRUCTNAME.AdvisoryNonFatalError 指示报告非致命错误被屏蔽的单个位。 DUMMYSTRUCTNAME.CorrectedInternalError
DUMMYSTRUCTNAME.HeaderLogOverflow DUMMYSTRUCTNAME.Reserved3
保留。 AsULONG
PCI_EXPRESS_CORRECTABLE_ERROR_MASK结构的内容的 ULONG 表示形式。

